import { GALLERY_ITEMS } from "../data";

export default function Gallery() {
  return (
    <section id="gallery" className="py-24 px-6 md:px-12 border-t border-yellow-500/10">
      <div className="max-w-6xl mx-auto">

        {/* Header */}
        <div className="text-center mb-16">
          <p className="text-xs font-bold tracking-widest uppercase text-yellow-600 mb-3">Works</p>
          <h2 className="font-serif font-black mb-4" style={{ fontSize: "clamp(2rem, 5vw, 3.5rem)", letterSpacing: "-0.03em" }}>
            Featured <span className="gold-text">Gallery</span>
          </h2>
          <div className="brush-line w-24 mx-auto mb-6" />
          <p className="text-yellow-100/40 max-w-xl mx-auto text-sm leading-relaxed">
            A curated glimpse into Subham's body of work — each piece a window into a different dimension of artistic expression.
          </p>
        </div>

        {/* Gallery grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
          {GALLERY_ITEMS.map((item, i) => (
            <div key={item.title} className="art-card group overflow-hidden cursor-pointer">
              {/* Art preview */}
              <div className={`relative h-52 bg-gradient-to-br ${item.color} flex items-center justify-center overflow-hidden`}>
                {/* Decorative lines */}
                <div className="absolute inset-0 opacity-20">
                  {[...Array(5)].map((_, j) => (
                    <div key={j} className="absolute border-t border-current"
                      style={{
                        top: `${20 + j * 16}%`,
                        left: "10%", right: "10%",
                        borderColor: item.accent,
                        opacity: 0.3 - j * 0.04,
                      }} />
                  ))}
                </div>

                {/* Center emoji */}
                <div className="relative z-10 text-7xl float" style={{ animationDelay: `${i * 0.2}s` }}>
                  {item.emoji}
                </div>

                {/* Hover overlay */}
                <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity duration-300"
                  style={{ background: `${item.accent}20`, backdropFilter: "blur(4px)" }}>
                  <div className="text-center">
                    <div className="text-white font-bold text-sm mb-1">View Artwork</div>
                    <div className="text-white/60 text-xs">Add your real artwork here</div>
                  </div>
                </div>

                {/* Medium badge */}
                <div className="absolute top-3 right-3 text-[10px] font-bold px-3 py-1.5 rounded-full"
                  style={{ background: `${item.accent}25`, color: item.accent, border: `1px solid ${item.accent}40` }}>
                  {item.medium}
                </div>

                {/* Number */}
                <div className="absolute top-3 left-3 font-serif text-xs font-bold opacity-40" style={{ color: item.accent }}>
                  {String(i + 1).padStart(2, "0")}
                </div>
              </div>

              {/* Info */}
              <div className="p-5">
                <h3 className="font-serif font-bold text-base mb-2 group-hover:text-yellow-300 transition-colors" style={{ color: item.accent }}>
                  {item.title}
                </h3>
                <p className="text-yellow-100/40 text-xs leading-relaxed">{item.desc}</p>
              </div>
            </div>
          ))}
        </div>

        {/* Note */}
        <div className="mt-12 text-center">
          <div className="inline-block px-6 py-4 rounded-2xl border border-yellow-500/20 bg-yellow-500/5">
            <p className="text-yellow-300/60 text-xs leading-relaxed">
              💡 <strong className="text-yellow-400">Artist's Note:</strong> Replace the gallery cards with real artwork images by adding image files to the <code className="bg-yellow-500/10 px-1 rounded">public/</code> folder and using <code className="bg-yellow-500/10 px-1 rounded">&lt;img src="/your-art.jpg" /&gt;</code>
            </p>
          </div>
        </div>
      </div>
    </section>
  );
}
